import re
from pathlib import Path

import pytest

AC_UID = "d02f6cfa9052329c"
AC_TYPE = "data"

REPO_ROOT = Path(__file__).resolve().parents[3]
TEST_WRITER_MD = REPO_ROOT / "agents" / "test-writer.md"


def _slice(text: str, start_re: str, end_re: str) -> str:
    m_start = re.search(start_re, text, re.MULTILINE)
    assert m_start, f"start anchor {start_re!r} not found in agents/test-writer.md"
    rest = text[m_start.start():]
    m_end = re.search(end_re, rest[1:], re.MULTILINE)  # skip the start match itself
    end_pos = m_end.start() + 1 if m_end else len(rest)
    return rest[:end_pos]


def test_AC_03():
    """
    GIVEN: agents/test-writer.md is read as text
    WHEN:  Procedure step 5 paragraph AND the Output JSON Report code fence are inspected separately (each scope-anchored)
    THEN:  step 5 paragraph mentions BOTH per-task active manifest path AND the global index file; the Output JSON Report's manifest_path field is the per-task path AND is NOT the global path
    """
    assert TEST_WRITER_MD.is_file(), f"missing: {TEST_WRITER_MD}"
    src = TEST_WRITER_MD.read_text(encoding="utf-8")

    # Scope 1: procedure step 5 paragraph
    step5 = _slice(src, r"^5\.\s+Compute the new manifest\.", r"^6\.\s+Return a structured report")
    assert "tests/generated/<task_id>/manifest.json" in step5, (
        "agents/test-writer.md procedure step 5 missing per-task manifest path"
    )
    # Forbid unqualified global write (without (global) or (index) annotation)
    bad_global = re.search(r"Write\s+`?tests/generated/manifest\.json`?(?!\s*\((?:global|index))", step5)
    assert bad_global is None, (
        f"agents/test-writer.md step 5 has unqualified global manifest write: {bad_global.group(0)!r}"
    )

    # Scope 2: Output JSON Report section
    report_scope = _slice(src, r"^## Output JSON Report", r"^## ")
    assert re.search(r'"manifest_path"\s*:\s*"tests/generated/<task_id>/manifest\.json"', report_scope), (
        "agents/test-writer.md Output JSON Report missing per-task manifest_path"
    )
    assert not re.search(r'"manifest_path"\s*:\s*"tests/generated/manifest\.json"', report_scope), (
        "agents/test-writer.md Output JSON Report incorrectly uses global manifest_path"
    )
